CREATE OR REPLACE FUNCTION fpa_acc_sort_prename_code (as_pre_code char) RETURNS varchar AS $body$
DECLARE

  ls_return char(5);

BEGIN  --ใช้เฉพาะยศของทหารเรือ ของ สหกรณ์ออมทรัพย์นาวิกโยธิน จำกัด
  if trim(both as_pre_code) in ('033','034','035','036','037','038') then  --พล
  case trim(both as_pre_code)
      when '035' then
        ls_return := '001';
      when '036' then
        ls_return := '002';
      when '037' then
        ls_return := '003';
      when '038' then
        ls_return := '004';
      when '033' then
        ls_return := '005';
      when '034' then
        ls_return := '006';
    end case;
  elsif (trim(both as_pre_code))::numeric  >= ('006')::numeric  and (trim(both as_pre_code))::numeric  <= ('031')::numeric  then   --
    ls_return := trim(both to_char((trim(both as_pre_code))::numeric  + 1 ,'000'));
  elsif trim(both as_pre_code) in ('039','040','041')  then
    ls_return := as_pre_code;
  elsif trim(both as_pre_code) ='000'  then  --ไม่ระบุให้ต่อท้ายสุด
    ls_return := 'a01';
  else
    ls_return := trim(both substr(trim(both as_pre_code),3,1))||trim(both substr(trim(both as_pre_code),2,1))||trim(both substr(trim(both as_pre_code),1,1));
  end if;


return   ls_return;
exception when others then CALL spa_dberror('FPA_ACC_SORT_PRENAME_CODE');
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
